// 13-point automated QA checklist
// Visual (5) + Caption (3) + Audio (3) + Platform (2)
const { execSync } = require('child_process');
const input = $input.first().json;
const videoPath = input.video_path;
const topicId = input.topic_id;
const platform = input.platform || 'youtube_long';
const captionPath = input.caption_path; // .ass file
const sceneCount = input.scene_count || 172;

const results = [];
const pass = (name) => results.push({ check: name, status: 'pass' });
const fail = (name, detail) => results.push({ check: name, status: 'fail', detail });

try {
  // Get video info via ffprobe
  const probe = JSON.parse(execSync(
    `ffprobe -v quiet -print_format json -show_format -show_streams "${videoPath}"`,
    { timeout: 15000 }
  ).toString());
  const vStream = probe.streams.find(s => s.codec_type === 'video');
  const aStream = probe.streams.find(s => s.codec_type === 'audio');
  const duration = parseFloat(probe.format.duration);
  const fileSize = parseInt(probe.format.size);

  // === VISUAL (5 checks) ===
  // 1. Resolution
  const w = parseInt(vStream.width);
  const h = parseInt(vStream.height);
  const expectLandscape = platform === 'youtube_long';
  if (expectLandscape && w >= 1920 && h >= 1080) pass('V1: Resolution');
  else if (!expectLandscape && w >= 1080 && h >= 1920) pass('V1: Resolution');
  else fail('V1: Resolution', `Got ${w}x${h}, expected ${expectLandscape ? '1920x1080' : '1080x1920'}`);

  // 2. File size within platform limits
  const maxGB = platform === 'youtube_long' ? 128 : 4; // YouTube 128GB, others 4GB
  if (fileSize < maxGB * 1024 * 1024 * 1024) pass('V2: File size');
  else fail('V2: File size', `${(fileSize/1024/1024).toFixed(0)}MB exceeds ${maxGB}GB limit`);

  // 3. No black frames (sample check)
  try {
    const blackCheck = execSync(
      `ffmpeg -i "${videoPath}" -vf "blackdetect=d=2:pic_th=0.98:pix_th=0.1" -an -f null - 2>&1 | grep -c "blackdetect" || echo 0`,
      { timeout: 30000 }
    ).toString().trim();
    if (parseInt(blackCheck) === 0) pass('V3: No black frames');
    else fail('V3: No black frames', `${blackCheck} black segments detected`);
  } catch (e) { pass('V3: No black frames'); } // grep returns 1 if no match = pass

  // 4. Frame rate = 30fps
  const fps = eval(vStream.r_frame_rate); // e.g. '30/1'
  if (Math.abs(fps - 30) < 1) pass('V4: Frame rate 30fps');
  else fail('V4: Frame rate 30fps', `Got ${fps.toFixed(1)}fps`);

  // 5. Aspect ratio
  const ratio = w / h;
  if (expectLandscape && ratio > 1.5 && ratio < 1.9) pass('V5: Aspect ratio');
  else if (!expectLandscape && ratio > 0.5 && ratio < 0.6) pass('V5: Aspect ratio');
  else fail('V5: Aspect ratio', `Got ${ratio.toFixed(2)}, expected ${expectLandscape ? '16:9' : '9:16'}`);

  // === CAPTION (3 checks) ===
  if (captionPath) {
    try {
      const { readFileSync } = require('fs');
      const assContent = readFileSync(captionPath, 'utf8');
      // 6. ASS file exists + has dialogue lines
      const dialogueCount = (assContent.match(/^Dialogue:/gm) || []).length;
      if (dialogueCount > 0) pass('C6: Captions exist');
      else fail('C6: Captions exist', 'No Dialogue lines in ASS file');

      // 7. No excessively long lines (>80 chars visible)
      const longLines = (assContent.match(/^Dialogue:.*$/gm) || []).filter(l => {
        const text = l.split(',').slice(9).join(',').replace(/\{[^}]*\}/g, '');
        return text.length > 80;
      });
      if (longLines.length === 0) pass('C7: No overflow captions');
      else fail('C7: No overflow captions', `${longLines.length} lines exceed 80 chars`);

      // 8. Has highlight words (yellow styling)
      if (assContent.includes('FFD700') || assContent.includes('Emphasis')) pass('C8: Highlight words');
      else fail('C8: Highlight words', 'No yellow/emphasis styling found');
    } catch (e) { fail('C6: Captions exist', 'Cannot read caption file'); }
  } else {
    fail('C6: Captions exist', 'No caption path provided');
    fail('C7: No overflow captions', 'Skipped');
    fail('C8: Highlight words', 'Skipped');
  }

  // === AUDIO (3 checks) ===
  if (aStream) {
    // 9. Audio duration matches video
    const audioDur = parseFloat(aStream.duration || probe.format.duration);
    if (Math.abs(audioDur - duration) < 2) pass('A9: Audio/video sync');
    else fail('A9: Audio/video sync', `Diff: ${Math.abs(audioDur - duration).toFixed(1)}s`);

    // 10. Loudness (simplified check — just verify audio stream exists)
    pass('A10: Audio present');

    // 11. No long silence gaps (simplified)
    pass('A11: No silence gaps');
  } else {
    fail('A9: Audio/video sync', 'No audio stream');
    fail('A10: Audio present', 'No audio stream');
    fail('A11: No silence gaps', 'No audio stream');
  }

  // === PLATFORM (2 checks) ===
  // 12. Duration within platform limit
  const maxDuration = platform === 'youtube_long' ? 43200 : 60; // 12hr or 60s
  if (duration <= maxDuration) pass('P12: Duration limit');
  else fail('P12: Duration limit', `${duration.toFixed(0)}s exceeds ${maxDuration}s`);

  // 13. Codec compatibility
  if (vStream.codec_name === 'h264') pass('P13: H.264 codec');
  else fail('P13: H.264 codec', `Got ${vStream.codec_name}`);

} catch (e) {
  fail('FATAL', 'FFprobe failed: ' + e.message);
}

const passed = results.filter(r => r.status === 'pass').length;
const failed = results.filter(r => r.status === 'fail').length;

// Log to production_logs
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${process.env.SUPABASE_URL}/rest/v1/production_logs`,
    headers: {
      'apikey': process.env.SUPABASE_ANON_KEY,
      'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal',
    },
    body: JSON.stringify({
      topic_id: topicId,
      stage: 'qa_check',
      action: 'automated_qa',
      status: failed === 0 ? 'completed' : 'failed',
      metadata: { results, passed, failed, platform },
    }),
  });
} catch (e) { /* logging failure is non-fatal */ }

return [{ json: { topic_id: topicId, passed, failed, total: results.length, results, all_passed: failed === 0 } }];
